set.insert(1);
set.insert(2);
let contains = set.contains(1);  // true

// LinkedList (doubly-linked list)
let mut list = LinkedList::new();
list.push_back(1);
list.push_front(0);
let front = list.pop_front();  // Option<i32>

// BTreeMap (sorted map)
let mut map = BTreeMap::new();
map.insert(3, "c");
map.insert(1, "a");
map.insert(2, "b");
let range = map.range(1..3);  // Iterate 1..3

// BTreeSet (sorted set)
let mut set = BTreeSet::new();
set.insert(3);
set.insert(1);
set.insert(2);
let range = set.range(1..3);  // Iterate 1..3

// Deque (double-ended queue)
let mut deque = Deque::new();
deque.push_back(1);
deque.push_front(0);
let front = deque.pop_front();  // Option<i32>
let back = deque.pop_back();    // Option<i32>

// PriorityQueue (heap)
let mut pq = PriorityQueue::new();
pq.push(3);
pq.push(1);
pq.push(2);
let max = pq.pop();  // Some(3)

// Trie (prefix tree)
let mut trie = Trie::new();
trie.insert("hello");
trie.insert("help");
let words = trie.autocomplete("hel");  // ["hello", "help"]

// Graph (adjacency list)
let mut graph = Graph::new();
graph.add_edge(0, 1);
graph.add_edge(1, 2);
let neighbors = graph.neighbors(0);  // [1]

// UnionFind (disjoint set)
let mut uf = UnionFind::new(5);
uf.union(0, 1);
uf.union(1, 2);
let connected = uf.find(0) == uf.find(2);  // true
```

