@router.post("/introspect")
async def introspect(
    current_user: dict = Depends(verify_token)
) -> JSONResponse:
    """
    Get GraphQL introspection data.
    """
    if not GRAPHQL_AVAILABLE:
        raise HTTPException(
            status_code=503,
            detail="GraphQL support not available."
        )

    try:
        # GraphQL introspection query
        introspection_query = """
        {
            __schema {
                types {
                    name
                    kind
                    description
                    fields {
                        name
                        type {
                            name
                            kind
                        }
                    }
                }
            }
        }
