async def _run_training(job_id: str, model_type: ModelType):
    """Background task to run training."""
    try:
        job = await training_pipeline.get_training_job(job_id)
        if not job:
            logger.error(f"Job {job_id} not found")
            return

        # Select appropriate trainer
        if model_type == ModelType.CIRCUIT_OPTIMIZATION:
            trainer = CircuitOptimizationTrainer()
        elif model_type == ModelType.RESOURCE_ESTIMATION:
            trainer = ResourceEstimationTrainer()
        elif model_type == ModelType.PATTERN_RECOGNITION:
            trainer = PatternRecognitionTrainer()
        else:
            logger.error(f"Unknown model type: {model_type}")
            return

        # Run training
        success, metrics = await trainer.train(job)

        if success:
            await training_pipeline.complete_training(job_id, metrics)
        else:
            await training_pipeline.fail_training(job_id, "Training failed")

    except Exception as e:
        logger.error(f"Error in training task: {e}")
        await training_pipeline.fail_training(job_id, str(e))

"""
WebSocket Router for real-time collaboration endpoints.

Provides WebSocket endpoints for collaborative editing, presence tracking,
and real-time communication.
"""

import logging
from typing import Optional
from uuid import uuid4

from fastapi import APIRouter, WebSocket, WebSocketDisconnect, Depends, HTTPException, status
from fastapi.responses import JSONResponse

from app.websocket.connection_manager import connection_manager, WebSocketMessage, MessageType
from app.websocket.message_handler import message_handler
from app.security.auth import verify_token

logger = logging.getLogger(__name__)

router = APIRouter(prefix="/api/v1/collaboration", tags=["collaboration"])


@router.websocket("/ws/{session_id}")
async def websocket_endpoint(websocket: WebSocket, session_id: str, token: str):
    """
    WebSocket endpoint for real-time collaboration.

    Clients connect with a session ID and JWT token.
    Messages are routed based on type (edit, presence, comment, etc.)
    """
    try:
        # Verify token
        user_data = verify_token(token)
        if not user_data:
            await websocket.close(code=status.WS_1008_POLICY_VIOLATION)
            return

        user_id = user_data.get("sub")

        # Connect user to session
        connection = await connection_manager.connect(websocket, session_id, user_id)
        if not connection:
            await websocket.close(code=status.WS_1011_SERVER_ERROR)
            return

        # Get session
        session = await connection_manager.get_session(session_id)

        # Send welcome message with initial state
        welcome_message = WebSocketMessage(
            type=MessageType.SYNC,
            session_id=session_id,
            user_id=user_id,
            timestamp=__import__("datetime").datetime.utcnow(),
            data={
                "content": session.content,
                "version": session.version,
                "participants": session.get_participants(),
                "connection_id": connection.connection_id
            }
        )
        await connection.send_message(welcome_message)

        # Broadcast user joined
        join_message = WebSocketMessage(
            type=MessageType.PRESENCE,
            session_id=session_id,
            user_id=user_id,
            timestamp=__import__("datetime").datetime.utcnow(),
            data={
                "presence_type": "user_joined",
                "user_id": user_id,
                "participants": session.get_participants()
            }
        )
        await session.broadcast_message(join_message, connection.connection_id)

        # Message loop
        while True:
            try:
                # Receive message
                received_message = await connection.receive_message()
                if not received_message:
                    break

                # Process message
                await message_handler.process_message(received_message, connection, session)

            except WebSocketDisconnect:
                break
            except Exception as e:
                logger.error(f"Error in message loop: {e}")
                break

    except Exception as e:
        logger.error(f"WebSocket error: {e}")

    finally:
        # Disconnect user
        if connection:
            await connection_manager.disconnect(connection)

            # Broadcast user left
            session = await connection_manager.get_session(session_id)
            if session:
                leave_message = WebSocketMessage(
                    type=MessageType.PRESENCE,
                    session_id=session_id,
                    user_id=user_id,
                    timestamp=__import__("datetime").datetime.utcnow(),
                    data={
                        "presence_type": "user_left",
                        "user_id": user_id,
                        "participants": session.get_participants()
                    }
                )
                await session.broadcast_message(leave_message)


