# ============================================================================
# Thread Pool
# ============================================================================

class ThreadPool:
    """Thread pool for parallel task execution."""

    def __init__(self, num_threads: int = None):
        """Create thread pool."""
        if num_threads is None:
            num_threads = multiprocessing.cpu_count()
        self.num_threads = num_threads
        self.executor = ThreadPoolExecutor(max_workers=num_threads)
        self.futures = []

    def execute(self, task: Callable) -> None:
        """Submit task to pool."""
        future = self.executor.submit(task)
        self.futures.append(future)

    def wait(self) -> None:
        """Wait for all tasks to complete."""
        for future in self.futures:
            future.result()
        self.futures.clear()

    def shutdown(self) -> None:
        """Shutdown thread pool."""
        self.executor.shutdown(wait=True)

    def __enter__(self):
        """Context manager entry."""
        return self

    def __exit__(self, exc_type, exc_val, exc_tb):
        """Context manager exit."""
        self.shutdown()


class ProcessPool:
    """Process pool for parallel task execution."""

    def __init__(self, num_processes: int = None):
        """Create process pool."""
        if num_processes is None:
            num_processes = multiprocessing.cpu_count()
        self.num_processes = num_processes
        self.executor = ProcessPoolExecutor(max_workers=num_processes)
        self.futures = []

    def execute(self, task: Callable) -> None:
        """Submit task to pool."""
        future = self.executor.submit(task)
        self.futures.append(future)

    def wait(self) -> None:
        """Wait for all tasks to complete."""
        for future in self.futures:
            future.result()
        self.futures.clear()

    def shutdown(self) -> None:
        """Shutdown process pool."""
        self.executor.shutdown(wait=True)


# ============================================================================
# Parallel Operations
# ============================================================================

def parallel_for(start: int, end: int, body: Callable[[int], None], 
                 num_threads: int = None) -> None:
    """Execute loop in parallel."""
    if num_threads is None:
        num_threads = multiprocessing.cpu_count()

    with ThreadPoolExecutor(max_workers=num_threads) as executor:
        futures = []
        for i in range(start, end):
            futures.append(executor.submit(body, i))
        for future in futures:
            future.result()


def parallel_map(data: List[T], func: Callable[[T], T], 
                 num_threads: int = None) -> List[T]:
    """Apply function to list in parallel."""
    if num_threads is None:
        num_threads = multiprocessing.cpu_count()

    with ThreadPoolExecutor(max_workers=num_threads) as executor:
        futures = [executor.submit(func, item) for item in data]
        return [future.result() for future in futures]


def parallel_reduce(data: List[T], init: T, func: Callable[[T, T], T],
                    num_threads: int = None) -> T:
    """Reduce list in parallel."""
    if num_threads is None:
        num_threads = multiprocessing.cpu_count()

    if not data:
        return init

    # Divide data into chunks
    chunk_size = max(1, len(data) // num_threads)
    chunks = [data[i:i + chunk_size] for i in range(0, len(data), chunk_size)]

    # Reduce each chunk
    with ThreadPoolExecutor(max_workers=num_threads) as executor:
        def reduce_chunk(chunk):
            result = init
            for item in chunk:
                result = func(result, item)
            return result

        futures = [executor.submit(reduce_chunk, chunk) for chunk in chunks]
        partial_results = [future.result() for future in futures]

    # Reduce partial results
    result = init
    for partial in partial_results:
        result = func(result, partial)

    return result


# ============================================================================
# Vectorization Support
# ============================================================================

def vectorize_operation(func: Callable, data: List[float]) -> List[float]:
    """Vectorize scalar function over array."""
    return [func(x) for x in data]


def simd_vector_add(a: List[float], b: List[float]) -> List[float]:
    """Add two vectors using SIMD."""
    a_arr = np.array(a, dtype=np.float32)
    b_arr = np.array(b, dtype=np.float32)
    return (a_arr + b_arr).tolist()


def simd_vector_mul(a: List[float], b: List[float]) -> List[float]:
    """Multiply two vectors using SIMD."""
    a_arr = np.array(a, dtype=np.float32)
    b_arr = np.array(b, dtype=np.float32)
    return (a_arr * b_arr).tolist()


def simd_dot_product(a: List[float], b: List[float]) -> float:
    """Calculate dot product using SIMD."""
    a_arr = np.array(a, dtype=np.float32)
    b_arr = np.array(b, dtype=np.float32)
    return float(np.dot(a_arr, b_arr))


def simd_matrix_mul(a: List[List[float]], b: List[List[float]]) -> List[List[float]]:
    """Multiply matrices using SIMD."""
    a_arr = np.array(a, dtype=np.float32)
    b_arr = np.array(b, dtype=np.float32)
    return np.matmul(a_arr, b_arr).tolist()


# ============================================================================
# Synchronization Primitives
# ============================================================================

class Mutex:
    """Mutual exclusion lock."""

    def __init__(self):
        """Create mutex."""
        self._lock = threading.Lock()

    def lock(self) -> None:
        """Acquire lock."""
        self._lock.acquire()

    def unlock(self) -> None:
        """Release lock."""
        self._lock.release()

    def try_lock(self) -> bool:
        """Try to acquire lock."""
        return self._lock.acquire(blocking=False)

    def __enter__(self):
        """Context manager entry."""
        self.lock()
        return self

    def __exit__(self, exc_type, exc_val, exc_tb):
        """Context manager exit."""
        self.unlock()


class Semaphore:
    """Semaphore for resource counting."""

    def __init__(self, count: int = 1):
        """Create semaphore."""
        self._semaphore = threading.Semaphore(count)

    def acquire(self) -> None:
        """Acquire semaphore."""
        self._semaphore.acquire()

    def release(self) -> None:
        """Release semaphore."""
        self._semaphore.release()

    def try_acquire(self) -> bool:
        """Try to acquire semaphore."""
        return self._semaphore.acquire(blocking=False)


class Barrier:
    """Barrier for thread synchronization."""

    def __init__(self, num_threads: int):
        """Create barrier."""
        self._barrier = threading.Barrier(num_threads)

    def wait(self) -> None:
        """Wait for all threads at barrier."""
        self._barrier.wait()


__all__ = [
    'Vec4f', 'Vec8f', 'Vec4d',
    'ThreadPool', 'ProcessPool',
    'parallel_for', 'parallel_map', 'parallel_reduce',
    'vectorize_operation', 'simd_vector_add', 'simd_vector_mul',
    'simd_dot_product', 'simd_matrix_mul',
    'Mutex', 'Semaphore', 'Barrier'
]

"""
SynQ Standard Library - Strings Module

Provides string manipulation, formatting, and regular expression operations.
"""

import re
import base64
import binascii
from typing import List, Optional, Tuple, Union


# ============================================================================
# Basic String Operations
# ============================================================================

def length(s: str) -> int:
    """Get string length."""
    return len(s)


def concat(*strings: str) -> str:
    """Concatenate multiple strings."""
    return ''.join(strings)


def split(s: str, delimiter: str = None, maxsplit: int = -1) -> List[str]:
    """Split string by delimiter."""
    if delimiter is None:
        return s.split()
    return s.split(delimiter, maxsplit)


def join(parts: List[str], separator: str = '') -> str:
    """Join list of strings with separator."""
    return separator.join(parts)


def trim(s: str) -> str:
    """Remove leading and trailing whitespace."""
    return s.strip()


def ltrim(s: str) -> str:
    """Remove leading whitespace."""
    return s.lstrip()


def rtrim(s: str) -> str:
    """Remove trailing whitespace."""
    return s.rstrip()


def uppercase(s: str) -> str:
    """Convert to uppercase."""
    return s.upper()


def lowercase(s: str) -> str:
    """Convert to lowercase."""
    return s.lower()


def capitalize(s: str) -> str:
    """Capitalize first character."""
    return s.capitalize()


def reverse(s: str) -> str:
    """Reverse string."""
    return s[::-1]


def contains(s: str, substring: str) -> bool:
    """Check if string contains substring."""
    return substring in s


def starts_with(s: str, prefix: str) -> bool:
    """Check if string starts with prefix."""
    return s.startswith(prefix)


def ends_with(s: str, suffix: str) -> bool:
    """Check if string ends with suffix."""
    return s.endswith(suffix)


def index_of(s: str, substring: str, start: int = 0) -> int:
    """Find index of substring (-1 if not found)."""
    try:
        return s.index(substring, start)
    except ValueError:
        return -1


def last_index_of(s: str, substring: str) -> int:
    """Find last index of substring (-1 if not found)."""
    try:
        return s.rindex(substring)
    except ValueError:
        return -1


def replace(s: str, old: str, new: str, count: int = -1) -> str:
    """Replace occurrences of substring."""
    if count == -1:
        return s.replace(old, new)
    return s.replace(old, new, count)


def substring(s: str, start: int, end: Optional[int] = None) -> str:
    """Extract substring."""
    if end is None:
        return s[start:]
    return s[start:end]


def repeat(s: str, count: int) -> str:
    """Repeat string count times."""
    if count < 0:
        raise ValueError("repeat: count must be non-negative")
    return s * count


def char_at(s: str, index: int) -> str:
    """Get character at index."""
    if not 0 <= index < len(s):
        raise IndexError("char_at: index out of bounds")
    return s[index]


def count(s: str, substring: str) -> int:
    """Count occurrences of substring."""
    return s.count(substring)


# ============================================================================
# Formatting Functions
# ============================================================================

def format(template: str, *args, **kwargs) -> str:
    """Format string with positional and keyword arguments."""
    try:
        return template.format(*args, **kwargs)
    except (IndexError, KeyError) as e:
        raise ValueError(f"format: {e}")


def sprintf(fmt: str, *args) -> str:
    """Format string using printf-style formatting."""
    try:
        return fmt % args if args else fmt
    except (TypeError, ValueError) as e:
        raise ValueError(f"sprintf: {e}")


def pad_left(s: str, width: int, fill: str = ' ') -> str:
    """Pad string on left to width."""
    if len(fill) != 1:
        raise ValueError("pad_left: fill must be single character")
    return s.rjust(width, fill)


def pad_right(s: str, width: int, fill: str = ' ') -> str:
    """Pad string on right to width."""
    if len(fill) != 1:
        raise ValueError("pad_right: fill must be single character")
    return s.ljust(width, fill)


def center(s: str, width: int, fill: str = ' ') -> str:
    """Center string in field of width."""
    if len(fill) != 1:
        raise ValueError("center: fill must be single character")
    return s.center(width, fill)


# ============================================================================
# Parsing Functions
# ============================================================================

def parse_int(s: str, base: int = 10) -> int:
    """Parse string as integer."""
    try:
        return int(s.strip(), base)
    except ValueError:
        raise ValueError(f"parse_int: '{s}' is not a valid integer")


def parse_float(s: str) -> float:
    """Parse string as float."""
    try:
        return float(s.strip())
    except ValueError:
        raise ValueError(f"parse_float: '{s}' is not a valid float")


def parse_bool(s: str) -> bool:
    """Parse string as boolean."""
    s_lower = s.lower().strip()
    if s_lower in ('true', '1', 'yes', 'on'):
        return True
    elif s_lower in ('false', '0', 'no', 'off'):
        return False
    else:
        raise ValueError(f"parse_bool: '{s}' is not a valid boolean")


def to_string(value) -> str:
    """Convert value to string."""
    if isinstance(value, bool):
        return 'true' if value else 'false'
    elif value is None:
        return 'null'
    return str(value)


# ============================================================================
# Regular Expressions
# ============================================================================

class Regex:
    """Regular expression wrapper."""

    def __init__(self, pattern: str, flags: int = 0):
        """Compile regular expression."""
        try:
            self.pattern = pattern
            self.regex = re.compile(pattern, flags)
        except re.error as e:
            raise ValueError(f"Regex: invalid pattern - {e}")

    def match(self, text: str) -> bool:
        """Check if regex matches text."""
        return self.regex.search(text) is not None

    def find(self, text: str) -> Optional[str]:
        """Find first match."""
        m = self.regex.search(text)
        return m.group(0) if m else None

    def find_all(self, text: str) -> List[str]:
        """Find all matches."""
        return self.regex.findall(text)

    def replace(self, text: str, replacement: str) -> str:
        """Replace all matches."""
        return self.regex.sub(replacement, text)

    def split(self, text: str) -> List[str]:
        """Split by regex."""
        return self.regex.split(text)


def regex_compile(pattern: str) -> Regex:
    """Compile regular expression."""
    return Regex(pattern)


def regex_match(regex: Regex, text: str) -> bool:
    """Check if regex matches text."""
    return regex.match(text)


def regex_find(regex: Regex, text: str) -> Optional[str]:
    """Find first match."""
    return regex.find(text)


def regex_find_all(regex: Regex, text: str) -> List[str]:
    """Find all matches."""
    return regex.find_all(text)


def regex_replace(regex: Regex, text: str, replacement: str) -> str:
    """Replace all matches."""
    return regex.replace(text, replacement)


# ============================================================================
# Encoding/Decoding Functions
# ============================================================================

def encode_utf8(s: str) -> bytes:
    """Encode string as UTF-8 bytes."""
    return s.encode('utf-8')


def decode_utf8(data: bytes) -> str:
    """Decode UTF-8 bytes as string."""
    try:
        return data.decode('utf-8')
    except UnicodeDecodeError as e:
        raise ValueError(f"decode_utf8: invalid UTF-8 - {e}")


def encode_base64(s: str) -> str:
    """Encode string as base64."""
    return base64.b64encode(s.encode('utf-8')).decode('ascii')


def decode_base64(s: str) -> str:
    """Decode base64 string."""
    try:
        return base64.b64decode(s).decode('utf-8')
    except (binascii.Error, UnicodeDecodeError) as e:
        raise ValueError(f"decode_base64: invalid base64 - {e}")


def encode_hex(s: str) -> str:
    """Encode string as hexadecimal."""
    return s.encode('utf-8').hex()


def decode_hex(s: str) -> str:
    """Decode hexadecimal string."""
    try:
        return bytes.fromhex(s).decode('utf-8')
    except (ValueError, UnicodeDecodeError) as e:
        raise ValueError(f"decode_hex: invalid hex - {e}")


def encode_url(s: str) -> str:
    """URL-encode string."""
    import urllib.parse
    return urllib.parse.quote(s)


def decode_url(s: str) -> str:
    """URL-decode string."""
    import urllib.parse
    return urllib.parse.unquote(s)


# ============================================================================
# Character Classification
# ============================================================================

def is_alpha(s: str) -> bool:
    """Check if all characters are alphabetic."""
    return s.isalpha()


def is_digit(s: str) -> bool:
    """Check if all characters are digits."""
    return s.isdigit()


def is_alnum(s: str) -> bool:
    """Check if all characters are alphanumeric."""
    return s.isalnum()


def is_space(s: str) -> bool:
    """Check if all characters are whitespace."""
    return s.isspace()


def is_upper(s: str) -> bool:
    """Check if all cased characters are uppercase."""
    return s.isupper()


def is_lower(s: str) -> bool:
    """Check if all cased characters are lowercase."""
    return s.islower()


# ============================================================================
# String Comparison
# ============================================================================

def equals(a: str, b: str) -> bool:
    """Check if strings are equal."""
    return a == b


def equals_ignore_case(a: str, b: str) -> bool:
    """Check if strings are equal (case-insensitive)."""
    return a.lower() == b.lower()


def compare(a: str, b: str) -> int:
    """Compare strings (-1, 0, 1)."""
    if a < b:
        return -1
    elif a > b:
        return 1
    else:
        return 0


def levenshtein_distance(a: str, b: str) -> int:
    """Calculate Levenshtein distance between strings."""
    if len(a) < len(b):
        a, b = b, a

    if len(b) == 0:
        return len(a)

    previous_row = range(len(b) + 1)
    for i, ca in enumerate(a):
        current_row = [i + 1]
        for j, cb in enumerate(b):
            insertions = previous_row[j + 1] + 1
            deletions = current_row[j] + 1
            substitutions = previous_row[j] + (ca != cb)
            current_row.append(min(insertions, deletions, substitutions))
        previous_row = current_row

    return previous_row[-1]


