void CopilotAgent::setMode(const std::string& modeStr) {
    if (modeMap.count(modeStr)) {
        mode_ = modeMap[modeStr];
        hooks_.setMode(mode_);
    } else {
        std::cerr << "[Copilot] Unknown mode: " << modeStr << std::endl;
    }
