int main(int argc, char* argv[]) {
    if (argc < 3) {
        std::cerr << "Usage: ./copilot_cli <mode> <plugin> [payload_json]\n";
        return 1;
    }

    std::string mode = argv[1];
    std::string plugin = argv[2];
    std::string payload_raw = (argc > 3) ? argv[3] : "{}";

    REPL repl;
    CopilotAgent agent(repl);
