#include <memory>
#include <stdexcept>
#include <cstdio>

namespace synq {

std::string ShellUtils::execute(const std::string& command) {
    std::array<char, 128> buffer;
    std::string result;

    FILE* pipe = popen(command.c_str(), "r");
    if (!pipe) return "[Shell error]";

    while (fgets(buffer.data(), buffer.size(), pipe)) {
        result += buffer.data();
    }

    pclose(pipe);
    return result;
}

}

