void logSkillUsage(const std::string& skill, const std::string& plugin, bool success) {
    std::ofstream log("logs/skill_usage.jsonl", std::ios::app);
    if (!log.is_open()) return;

    std::time_t now = std::time(nullptr);
    log << nlohmann::json{
        {"timestamp", now},
        {"skill", skill},
        {"plugin", plugin},
        {"success", success}
    }.dump() << "\n";

    log.close();
}

