// Generate login URL at runtime so redirect URI reflects the current origin.
export const getLoginUrl = () => {
  const oauthPortalUrl = import.meta.env.VITE_OAUTH_PORTAL_URL;
  const appId = import.meta.env.VITE_APP_ID;
  const redirectUri = `${window.location.origin}/api/oauth/callback`;
  const state = btoa(redirectUri);

  const url = new URL(`${oauthPortalUrl}/app-auth`);
  url.searchParams.set("appId", appId);
  url.searchParams.set("redirectUri", redirectUri);
  url.searchParams.set("state", state);
  url.searchParams.set("type", "signIn");

  return url.toString();
};

import { useRef } from "react";
import { usePersistFn } from "./usePersistFn";

export interface UseCompositionReturn<
  T extends HTMLInputElement | HTMLTextAreaElement,
> {
  onCompositionStart: React.CompositionEventHandler<T>;
  onCompositionEnd: React.CompositionEventHandler<T>;
  onKeyDown: React.KeyboardEventHandler<T>;
  isComposing: () => boolean;
}

export interface UseCompositionOptions<
  T extends HTMLInputElement | HTMLTextAreaElement,
> {
  onKeyDown?: React.KeyboardEventHandler<T>;
  onCompositionStart?: React.CompositionEventHandler<T>;
  onCompositionEnd?: React.CompositionEventHandler<T>;
}

type TimerResponse = ReturnType<typeof setTimeout>;

export function useComposition<
  T extends HTMLInputElement | HTMLTextAreaElement = HTMLInputElement,
>(options: UseCompositionOptions<T> = {}): UseCompositionReturn<T> {
  const {
    onKeyDown: originalOnKeyDown,
    onCompositionStart: originalOnCompositionStart,
    onCompositionEnd: originalOnCompositionEnd,
  } = options;

  const c = useRef(false);
  const timer = useRef<TimerResponse | null>(null);
  const timer2 = useRef<TimerResponse | null>(null);

  const onCompositionStart = usePersistFn((e: React.CompositionEvent<T>) => {
    if (timer.current) {
      clearTimeout(timer.current);
      timer.current = null;
    }
    if (timer2.current) {
      clearTimeout(timer2.current);
      timer2.current = null;
    }
    c.current = true;
    originalOnCompositionStart?.(e);
  });

  const onCompositionEnd = usePersistFn((e: React.CompositionEvent<T>) => {
    // 使用两层 setTimeout 来处理 Safari 浏览器中 compositionEnd 先于 onKeyDown 触发的问题
    timer.current = setTimeout(() => {
      timer2.current = setTimeout(() => {
        c.current = false;
      });
    });
    originalOnCompositionEnd?.(e);
  });

  const onKeyDown = usePersistFn((e: React.KeyboardEvent<T>) => {
    // 在 composition 状态下，阻止 ESC 和 Enter（非 shift+Enter）事件的冒泡
    if (
      c.current &&
      (e.key === "Escape" || (e.key === "Enter" && !e.shiftKey))
    ) {
      e.stopPropagation();
      return;
    }
    originalOnKeyDown?.(e);
  });

  const isComposing = usePersistFn(() => {
    return c.current;
  });

  return {
    onCompositionStart,
    onCompositionEnd,
    onKeyDown,
    isComposing,
  };
}

/**
 * useOTEngine Hook
 * Manages operational transformation for collaborative editing
 */

import { useCallback, useRef, useState } from 'react';
import { OTEngine, Operation } from '@/lib/ot-engine';
import { useCollaboration } from '@/contexts/CollaborationContext';

export const useOTEngine = () => {
  const engineRef = useRef(new OTEngine());
  const [revision, setRevision] = useState(0);
  const [canUndo, setCanUndo] = useState(false);
  const [canRedo, setCanRedo] = useState(false);
  const { sendEdit, onMessage } = useCollaboration();

  // Apply local operation
  const applyLocalOperation = useCallback(
    (operation: Operation) => {
      const result = engineRef.current.applyLocalOperation(operation);
      setRevision(result.revision);
      setCanUndo(engineRef.current.canUndo());
      setCanRedo(engineRef.current.canRedo());

      // Send to server
      sendEdit(operation);

      return result;
    },
    [sendEdit]
  );

  // Apply remote operation
  const applyRemoteOperation = useCallback(
    (remoteOp: Operation, remoteRevision: number) => {
      const transformedOp = engineRef.current.applyRemoteOperation(remoteOp, remoteRevision);
      setRevision(engineRef.current.getRevision());
      return transformedOp;
    },
    []
  );

  // Transform operations
  const transform = useCallback((op1: Operation, op2: Operation) => {
    return engineRef.current.transform(op1, op2);
  }, []);

  // Apply operation to text
  const applyToText = useCallback((text: string, operation: Operation) => {
    return engineRef.current.applyToText(text, operation);
  }, []);

  // Undo
  const undo = useCallback(() => {
    const undoOp = engineRef.current.undo();
    setCanUndo(engineRef.current.canUndo());
    setCanRedo(engineRef.current.canRedo());
    return undoOp;
  }, []);

  // Redo
  const redo = useCallback(() => {
    const redoOp = engineRef.current.redo();
    setCanUndo(engineRef.current.canUndo());
    setCanRedo(engineRef.current.canRedo());
    return redoOp;
  }, []);

  // Get history
  const getHistory = useCallback(() => {
    return engineRef.current.getHistory();
  }, []);

  // Register remote edit handler
  onMessage('edit', (message) => {
    if (message.data.operation) {
      applyRemoteOperation(message.data.operation, message.revision || 0);
    }
  });

  return {
    applyLocalOperation,
    applyRemoteOperation,
    transform,
    applyToText,
    undo,
    redo,
    canUndo,
    canRedo,
    getHistory,
    revision,
  };
};

import { useRef } from "react";

type noop = (...args: any[]) => any;

/**
 * usePersistFn instead of useCallback to reduce cognitive load
 */
export function usePersistFn<T extends noop>(fn: T) {
  const fnRef = useRef<T>(fn);
  fnRef.current = fn;

  const persistFn = useRef<T>(null);
  if (!persistFn.current) {
    persistFn.current = function (this: unknown, ...args) {
      return fnRef.current!.apply(this, args);
    } as T;
  }

  return persistFn.current!;
}

/**
 * usePresenceTracking Hook
 * Tracks cursor position and selection, with throttling to reduce network traffic
 */

import { useEffect, useRef, useCallback } from 'react';
import { useCollaboration } from '@/contexts/CollaborationContext';

interface UsePresenceTrackingOptions {
  throttleMs?: number;
  editorRef?: React.RefObject<HTMLTextAreaElement | HTMLDivElement>;
}

export const usePresenceTracking = (options: UsePresenceTrackingOptions = {}) => {
  const { throttleMs = 100 } = options;
  const { updatePresence } = useCollaboration();

  const lastUpdateRef = useRef<number>(0);
  const throttleTimerRef = useRef<NodeJS.Timeout | null>(null);

  const trackPresence = useCallback(
    (cursorPosition: number, selectionStart: number, selectionEnd: number) => {
      const now = Date.now();
      const timeSinceLastUpdate = now - lastUpdateRef.current;

      if (timeSinceLastUpdate >= throttleMs) {
        // Enough time has passed, send immediately
        updatePresence(cursorPosition, selectionStart, selectionEnd);
        lastUpdateRef.current = now;
      } else {
        // Schedule for later
        if (throttleTimerRef.current) {
          clearTimeout(throttleTimerRef.current);
        }

        throttleTimerRef.current = setTimeout(() => {
          updatePresence(cursorPosition, selectionStart, selectionEnd);
          lastUpdateRef.current = Date.now();
        }, throttleMs - timeSinceLastUpdate);
      }
    },
    [updatePresence, throttleMs]
  );

  // Cleanup timer on unmount
  useEffect(() => {
    return () => {
      if (throttleTimerRef.current) {
        clearTimeout(throttleTimerRef.current);
      }
    };
  }, []);

  return { trackPresence };
};

/**
 * Hook to track cursor position from textarea or contenteditable
 */
export const useCursorTracking = (editorRef: React.RefObject<HTMLTextAreaElement | HTMLDivElement>) => {
  const { trackPresence } = usePresenceTracking();

  const handleSelectionChange = useCallback(() => {
    if (!editorRef.current) {
      return;
    }

    let cursorPosition = 0;
    let selectionStart = 0;
    let selectionEnd = 0;

    if (editorRef.current instanceof HTMLTextAreaElement) {
      cursorPosition = editorRef.current.selectionStart;
      selectionStart = editorRef.current.selectionStart;
      selectionEnd = editorRef.current.selectionEnd;
    } else {
      // For contenteditable
      const selection = window.getSelection();
      if (selection && selection.rangeCount > 0) {
        const range = selection.getRangeAt(0);
        const preCaretRange = range.cloneRange();
        preCaretRange.selectNodeContents(editorRef.current);
        preCaretRange.setEnd(range.endContainer, range.endOffset);
        cursorPosition = preCaretRange.toString().length;
        selectionStart = cursorPosition;
        selectionEnd = cursorPosition;
      }
    }

    trackPresence(cursorPosition, selectionStart, selectionEnd);
  }, [editorRef, trackPresence]);

  useEffect(() => {
    if (!editorRef.current) {
      return;
    }

    editorRef.current.addEventListener('click', handleSelectionChange);
    editorRef.current.addEventListener('keyup', handleSelectionChange);
    editorRef.current.addEventListener('mouseup', handleSelectionChange);

    return () => {
      if (!editorRef.current) {
        return;
      }
      editorRef.current.removeEventListener('click', handleSelectionChange);
      editorRef.current.removeEventListener('keyup', handleSelectionChange);
      editorRef.current.removeEventListener('mouseup', handleSelectionChange);
    };
  }, [editorRef, handleSelectionChange]);
};

