/**
 * GraphQL Client
 *
 * Provides type-safe GraphQL queries and mutations
 * for fetching circuits, jobs, models, and collaboration data
 */

import { useState, useCallback } from 'react';

export interface GraphQLError {
  message: string;
  locations?: Array<{ line: number; column: number }>;
  path?: string[];
}

export interface GraphQLResponse<T> {
  data?: T;
  errors?: GraphQLError[];
}

export interface Circuit {
  id: string;
  name: string;
  qubits: number;
  gates: Array<{
    type: string;
    qubits: number[];
    params?: Record<string, number>;
  }>;
  createdAt: string;
  updatedAt: string;
}

export interface Job {
  id: string;
  circuitId: string;
  backend: string;
  status: 'pending' | 'running' | 'completed' | 'failed';
  result?: Record<string, any>;
  createdAt: string;
  completedAt?: string;
}

export interface MLModel {
  id: string;
  name: string;
  type: 'circuit_optimization' | 'resource_estimation' | 'pattern_recognition';
  version: string;
  status: 'training' | 'deployed' | 'archived';
  accuracy?: number;
  createdAt: string;
}

export interface TrainingJob {
  id: string;
  modelId: string;
  status: 'pending' | 'running' | 'completed' | 'failed';
  epochs: number;
  batchSize: number;
  accuracy?: number;
  loss?: number;
  startedAt: string;
  completedAt?: string;
}

export interface CollaborationSession {
  id: string;
  name: string;
  circuitId: string;
  participants: Array<{
    userId: string;
    name: string;
    role: 'owner' | 'editor' | 'viewer';
    joinedAt: string;
  }>;
  createdAt: string;
}

export interface Comment {
  id: string;
  sessionId: string;
  line: number;
  author: string;
  content: string;
  resolved: boolean;
  createdAt: string;
  replies: Comment[];
}

class GraphQLClient {
  private url: string;
  private token: string;

  constructor(url: string, token: string) {
    this.url = url;
    this.token = token;
  }

  async query<T>(query: string, variables?: Record<string, any>): Promise<GraphQLResponse<T>> {
    try {
      const response = await fetch(this.url, {
        method: 'POST',
        headers: {
          'Content-Type': 'application/json',
          'Authorization': `Bearer ${this.token}`
        },
        body: JSON.stringify({ query, variables })
      });

      if (!response.ok) {
        throw new Error(`HTTP ${response.status}: ${response.statusText}`);
      }

      return await response.json();
    } catch (error) {
      return {
        errors: [
          {
            message: error instanceof Error ? error.message : 'Unknown error'
          }
        ]
      };
    }
  }

  async mutation<T>(mutation: string, variables?: Record<string, any>): Promise<GraphQLResponse<T>> {
    return this.query<T>(mutation, variables);
  }

  // Circuit queries
  async getCircuit(id: string): Promise<Circuit | null> {
    const query = `
      query GetCircuit($id: ID!) {
        circuit(id: $id) {
          id
          name
          qubits
          gates {
            type
            qubits
            params
          }
          createdAt
          updatedAt
        }
      }
    `;

    const response = await this.query<{ circuit: Circuit }>(query, { id });
    return response.data?.circuit || null;
  }

  async listCircuits(limit: number = 10, offset: number = 0): Promise<Circuit[]> {
    const query = `
      query ListCircuits($limit: Int!, $offset: Int!) {
        circuits(limit: $limit, offset: $offset) {
          id
          name
          qubits
          createdAt
          updatedAt
        }
      }
    `;

    const response = await this.query<{ circuits: Circuit[] }>(query, { limit, offset });
    return response.data?.circuits || [];
  }

  async createCircuit(name: string, qubits: number): Promise<Circuit | null> {
    const mutation = `
      mutation CreateCircuit($name: String!, $qubits: Int!) {
        createCircuit(name: $name, qubits: $qubits) {
          id
          name
          qubits
          createdAt
        }
      }
    `;

    const response = await this.mutation<{ createCircuit: Circuit }>(mutation, { name, qubits });
    return response.data?.createCircuit || null;
  }

  // Job queries
  async getJob(id: string): Promise<Job | null> {
    const query = `
      query GetJob($id: ID!) {
        job(id: $id) {
          id
          circuitId
          backend
          status
          result
          createdAt
          completedAt
        }
      }
    `;

    const response = await this.query<{ job: Job }>(query, { id });
    return response.data?.job || null;
  }

  async listJobs(status?: string, limit: number = 10): Promise<Job[]> {
    const query = `
      query ListJobs($status: String, $limit: Int!) {
        jobs(status: $status, limit: $limit) {
          id
          circuitId
          backend
          status
          createdAt
        }
      }
    `;

    const response = await this.query<{ jobs: Job[] }>(query, { status, limit });
    return response.data?.jobs || [];
  }

  async submitJob(circuitId: string, backend: string): Promise<Job | null> {
    const mutation = `
      mutation SubmitJob($circuitId: ID!, $backend: String!) {
        submitJob(circuitId: $circuitId, backend: $backend) {
          id
          circuitId
          backend
          status
          createdAt
        }
      }
    `;

    const response = await this.mutation<{ submitJob: Job }>(mutation, { circuitId, backend });
    return response.data?.submitJob || null;
  }

  // ML Model queries
  async getMLModel(id: string): Promise<MLModel | null> {
    const query = `
      query GetMLModel($id: ID!) {
        mlModel(id: $id) {
          id
          name
          type
          version
          status
          accuracy
          createdAt
        }
      }
    `;

    const response = await this.query<{ mlModel: MLModel }>(query, { id });
    return response.data?.mlModel || null;
  }

  async listMLModels(type?: string, status?: string): Promise<MLModel[]> {
    const query = `
      query ListMLModels($type: String, $status: String) {
        mlModels(type: $type, status: $status) {
          id
          name
          type
          version
          status
          accuracy
          createdAt
        }
      }
    `;

    const response = await this.query<{ mlModels: MLModel[] }>(query, { type, status });
    return response.data?.mlModels || [];
  }

  async createMLModel(name: string, type: string, version: string): Promise<MLModel | null> {
    const mutation = `
      mutation CreateMLModel($name: String!, $type: String!, $version: String!) {
        createMLModel(name: $name, type: $type, version: $version) {
          id
          name
          type
          version
          status
          createdAt
        }
      }
    `;

    const response = await this.mutation<{ createMLModel: MLModel }>(mutation, { name, type, version });
    return response.data?.createMLModel || null;
  }

  // Collaboration queries
  async getCollaborationSession(id: string): Promise<CollaborationSession | null> {
    const query = `
      query GetSession($id: ID!) {
        collaborationSession(id: $id) {
          id
          name
          circuitId
          participants {
            userId
            name
            role
            joinedAt
          }
          createdAt
        }
      }
    `;

    const response = await this.query<{ collaborationSession: CollaborationSession }>(query, { id });
    return response.data?.collaborationSession || null;
  }

  async listCollaborationSessions(): Promise<CollaborationSession[]> {
    const query = `
      query ListSessions {
        collaborationSessions {
          id
          name
          circuitId
          participants {
            userId
            name
            role
          }
          createdAt
        }
      }
    `;

    const response = await this.query<{ collaborationSessions: CollaborationSession[] }>(query);
    return response.data?.collaborationSessions || [];
  }

  async createCollaborationSession(name: string, circuitId: string): Promise<CollaborationSession | null> {
    const mutation = `
      mutation CreateSession($name: String!, $circuitId: ID!) {
        createCollaborationSession(name: $name, circuitId: $circuitId) {
          id
          name
          circuitId
          participants {
            userId
            name
            role
          }
          createdAt
        }
      }
    `;

    const response = await this.mutation<{ createCollaborationSession: CollaborationSession }>(
      mutation,
      { name, circuitId }
    );
    return response.data?.createCollaborationSession || null;
  }

  // Comment queries
  async getSessionComments(sessionId: string, resolved?: boolean): Promise<Comment[]> {
    const query = `
      query GetComments($sessionId: ID!, $resolved: Boolean) {
        sessionComments(sessionId: $sessionId, resolved: $resolved) {
          id
          sessionId
          line
          author
          content
          resolved
          createdAt
          replies {
            id
            author
            content
            createdAt
          }
        }
      }
    `;

    const response = await this.query<{ sessionComments: Comment[] }>(query, { sessionId, resolved });
    return response.data?.sessionComments || [];
  }

  async addComment(sessionId: string, line: number, content: string): Promise<Comment | null> {
    const mutation = `
      mutation AddComment($sessionId: ID!, $line: Int!, $content: String!) {
        addComment(sessionId: $sessionId, line: $line, content: $content) {
          id
          sessionId
          line
          author
          content
          resolved
          createdAt
        }
      }
    `;

    const response = await this.mutation<{ addComment: Comment }>(mutation, { sessionId, line, content });
    return response.data?.addComment || null;
  }
}

export default GraphQLClient;

// React hooks for GraphQL queries
export const useGraphQLQuery = <T,>(
  client: GraphQLClient,
  query: string,
  variables?: Record<string, any>
) => {
  const [data, setData] = useState<T | null>(null);
  const [loading, setLoading] = useState(false);
  const [error, setError] = useState<string | null>(null);

  const execute = useCallback(async () => {
    setLoading(true);
    setError(null);

    try {
      const response = await client.query<T>(query, variables);

      if (response.errors) {
        setError(response.errors[0]?.message || 'Unknown error');
      } else if (response.data) {
        setData(response.data);
      }
    } catch (err) {
      setError(err instanceof Error ? err.message : 'Unknown error');
    } finally {
      setLoading(false);
    }
  }, [client, query, variables]);

  return { data, loading, error, execute };
};

export const useGraphQLMutation = <T,>(
  client: GraphQLClient,
  mutation: string
) => {
  const [data, setData] = useState<T | null>(null);
  const [loading, setLoading] = useState(false);
  const [error, setError] = useState<string | null>(null);

  const execute = useCallback(
    async (variables?: Record<string, any>) => {
      setLoading(true);
      setError(null);

      try {
        const response = await client.mutation<T>(mutation, variables);

        if (response.errors) {
          setError(response.errors[0]?.message || 'Unknown error');
        } else if (response.data) {
          setData(response.data);
        }
      } catch (err) {
        setError(err instanceof Error ? err.message : 'Unknown error');
      } finally {
        setLoading(false);
      }
    },
    [client, mutation]
  );

  return { data, loading, error, execute };
};

/**
 * Operational Transformation (OT) Engine
 * Implements conflict-free concurrent editing with OT algorithm
 */

export type OperationType = 'insert' | 'delete' | 'retain';

export interface Operation {
  type: OperationType;
  position?: number;
  content?: string;
  length?: number;
}

export interface TransformedOperation {
  operation: Operation;
  revision: number;
}

/**
 * OT Engine for managing concurrent edits
 */
export class OTEngine {
  private history: Operation[] = [];
  private revision: number = 0;
  private pendingOperations: Operation[] = [];
  private undoStack: Operation[] = [];
  private redoStack: Operation[] = [];

  /**
   * Apply a local operation
   */
  public applyLocalOperation(operation: Operation): TransformedOperation {
    // Add to history
    this.history.push(operation);
    this.revision++;

    // Clear redo stack on new operation
    this.redoStack = [];

    // Add to undo stack
    this.undoStack.push(this.invertOperation(operation));

    return {
      operation,
      revision: this.revision,
    };
  }

  /**
   * Apply a remote operation
   */
  public applyRemoteOperation(remoteOp: Operation, remoteRevision: number): Operation {
    // Transform remote operation against all pending local operations
    let transformedOp = remoteOp;

    for (const pendingOp of this.pendingOperations) {
      transformedOp = this.transform(transformedOp, pendingOp)[0];
    }

    // Add to history
    this.history.push(transformedOp);
    this.revision++;

    return transformedOp;
  }

  /**
   * Transform two operations against each other
   * Returns [op1', op2'] where op1' is op1 transformed against op2
   */
  public transform(op1: Operation, op2: Operation): [Operation, Operation] {
    // If both operations are on the same position, apply priority
    if (op1.type === 'insert' && op2.type === 'insert') {
      if (op1.position === op2.position) {
        // Priority: op1 comes first if position is same
        return [
          op1,
          { type: 'insert', position: (op2.position || 0) + (op1.content?.length || 0), content: op2.content },
        ];
      } else if ((op1.position || 0) < (op2.position || 0)) {
        return [op1, { type: 'insert', position: (op2.position || 0) + (op1.content?.length || 0), content: op2.content }];
      } else {
        return [{ type: 'insert', position: (op1.position || 0) + (op2.content?.length || 0), content: op1.content }, op2];
      }
    }

    if (op1.type === 'insert' && op2.type === 'delete') {
      const insertPos = op1.position || 0;
      const deletePos = op2.position || 0;
      const deleteLen = op2.length || 0;

      if (insertPos < deletePos) {
        return [op1, { type: 'delete', position: deletePos + (op1.content?.length || 0), length: deleteLen }];
      } else if (insertPos >= deletePos + deleteLen) {
        return [{ type: 'insert', position: insertPos - deleteLen, content: op1.content }, op2];
      } else {
        return [op1, { type: 'delete', position: deletePos, length: deleteLen }];
      }
    }

    if (op1.type === 'delete' && op2.type === 'insert') {
      const deletePos = op1.position || 0;
      const deleteLen = op1.length || 0;
      const insertPos = op2.position || 0;

      if (deletePos + deleteLen <= insertPos) {
        return [op1, { type: 'insert', position: insertPos - deleteLen, content: op2.content }];
      } else if (deletePos >= insertPos) {
        return [{ type: 'delete', position: deletePos + (op2.content?.length || 0), length: deleteLen }, op2];
      } else {
        return [op1, { type: 'insert', position: insertPos, content: op2.content }];
      }
    }

    if (op1.type === 'delete' && op2.type === 'delete') {
      const deletePos1 = op1.position || 0;
      const deleteLen1 = op1.length || 0;
      const deletePos2 = op2.position || 0;
      const deleteLen2 = op2.length || 0;

      if (deletePos1 + deleteLen1 <= deletePos2) {
        return [op1, { type: 'delete', position: deletePos2 - deleteLen1, length: deleteLen2 }];
      } else if (deletePos2 + deleteLen2 <= deletePos1) {
        return [{ type: 'delete', position: deletePos1 - deleteLen2, length: deleteLen1 }, op2];
      } else {
        // Overlapping deletes - adjust positions
        const newPos1 = Math.min(deletePos1, deletePos2);
        const newLen1 = Math.max(deletePos1 + deleteLen1, deletePos2 + deleteLen2) - newPos1;
        return [
          { type: 'delete', position: newPos1, length: newLen1 },
          { type: 'delete', position: newPos1, length: 0 },
        ];
      }
    }

    // Default: return operations unchanged
    return [op1, op2];
  }

  /**
   * Compose two operations into one
   */
  public compose(op1: Operation, op2: Operation): Operation {
    if (op1.type === 'insert' && op2.type === 'insert') {
      if ((op1.position || 0) + (op1.content?.length || 0) === (op2.position || 0)) {
        return {
          type: 'insert',
          position: op1.position,
          content: (op1.content || '') + (op2.content || ''),
        };
      }
    }

    if (op1.type === 'delete' && op2.type === 'delete') {
      if (op1.position === op2.position) {
        return {
          type: 'delete',
          position: op1.position,
          length: (op1.length || 0) + (op2.length || 0),
        };
      }
    }

    // Can't compose, return first operation
    return op1;
  }

  /**
   * Invert an operation (for undo)
   */
  public invertOperation(operation: Operation): Operation {
    if (operation.type === 'insert') {
      return {
        type: 'delete',
        position: operation.position,
        length: operation.content?.length || 0,
      };
    } else if (operation.type === 'delete') {
      return {
        type: 'insert',
        position: operation.position,
        content: '', // We don't store the deleted content here
      };
    }
    return operation;
  }

  /**
   * Apply operation to text
   */
  public applyToText(text: string, operation: Operation): string {
    if (operation.type === 'insert') {
      const pos = operation.position || 0;
      return text.slice(0, pos) + (operation.content || '') + text.slice(pos);
    } else if (operation.type === 'delete') {
      const pos = operation.position || 0;
      const len = operation.length || 0;
      return text.slice(0, pos) + text.slice(pos + len);
    }
    return text;
  }

  /**
   * Get operation history
   */
  public getHistory(): Operation[] {
    return [...this.history];
  }

  /**
   * Get current revision
   */
  public getRevision(): number {
    return this.revision;
  }

  /**
   * Add pending operation
   */
  public addPendingOperation(operation: Operation): void {
    this.pendingOperations.push(operation);
  }

  /**
   * Clear pending operations
   */
  public clearPendingOperations(): void {
    this.pendingOperations = [];
  }

  /**
   * Undo last operation
   */
  public undo(): Operation | null {
    if (this.undoStack.length === 0) {
      return null;
    }

    const undoOp = this.undoStack.pop()!;
    this.redoStack.push(undoOp);
    return undoOp;
  }

  /**
   * Redo last undone operation
   */
  public redo(): Operation | null {
    if (this.redoStack.length === 0) {
      return null;
    }

    const redoOp = this.redoStack.pop()!;
    this.undoStack.push(redoOp);
    return redoOp;
  }

  /**
   * Can undo
   */
  public canUndo(): boolean {
    return this.undoStack.length > 0;
  }

  /**
   * Can redo
   */
  public canRedo(): boolean {
    return this.redoStack.length > 0;
  }
}

/**
 * Helper function to create insert operation
 */
export function createInsertOperation(position: number, content: string): Operation {
  return {
    type: 'insert',
    position,
    content,
  };
}

/**
 * Helper function to create delete operation
 */
export function createDeleteOperation(position: number, length: number): Operation {
  return {
    type: 'delete',
    position,
    length,
  };
}

/**
 * Helper function to create retain operation
 */
export function createRetainOperation(length: number): Operation {
  return {
    type: 'retain',
    length,
  };
}

/**
 * Serialize operation to JSON
 */
export function serializeOperation(operation: Operation): string {
  return JSON.stringify(operation);
}

/**
 * Deserialize operation from JSON
 */
export function deserializeOperation(json: string): Operation {
  return JSON.parse(json);
}

