/**
 * Secure WebSocket Client with Authentication and Security Features
 *
 * Provides authenticated WebSocket connections with:
 * - JWT token-based authentication
 * - Automatic reconnection with exponential backoff
 * - Message rate limiting
 * - Security validation
 * - Connection health monitoring
 */

export interface WebSocketConfig {
  url: string;
  token: string;
  sessionId: string;
  maxReconnectAttempts?: number;
  initialReconnectDelay?: number;
  maxReconnectDelay?: number;
  heartbeatInterval?: number;
}

export interface WebSocketMessage {
  type: string;
  sessionId: string;
  userId: string;
  timestamp: string;
  [key: string]: any;
}

export interface ConnectionStats {
  messagesReceived: number;
  messagesSent: number;
  reconnectAttempts: number;
  lastMessageTime: string | null;
  connectionDuration: number;
  averageLatency: number;
}

export class SecureWebSocketClient {
  private ws: WebSocket | null = null;
  private url: string;
  private token: string;
  private sessionId: string;
  private userId: string = '';
  private messageHandlers: Map<string, Function[]> = new Map();
  private messageQueue: WebSocketMessage[] = [];
  private reconnectAttempts = 0;
  private maxReconnectAttempts: number;
  private initialReconnectDelay: number;
  private maxReconnectDelay: number;
  private currentReconnectDelay: number;
  private heartbeatInterval: number;
  private heartbeatTimer: NodeJS.Timeout | null = null;
  private isConnected = false;
  private isAuthenticated = false;
  private stats: ConnectionStats = {
    messagesReceived: 0,
    messagesSent: 0,
    reconnectAttempts: 0,
    lastMessageTime: null,
    connectionDuration: 0,
    averageLatency: 0
  };
  private connectionStartTime: number = 0;
  private latencies: number[] = [];

  constructor(config: WebSocketConfig) {
    this.url = config.url;
    this.token = config.token;
    this.sessionId = config.sessionId;
    this.maxReconnectAttempts = config.maxReconnectAttempts || 10;
    this.initialReconnectDelay = config.initialReconnectDelay || 1000;
    this.maxReconnectDelay = config.maxReconnectDelay || 30000;
    this.currentReconnectDelay = this.initialReconnectDelay;
    this.heartbeatInterval = config.heartbeatInterval || 30000;
  }

  /**
   * Connect to WebSocket server
   */
  async connect(): Promise<boolean> {
    return new Promise((resolve) => {
      try {
        this.ws = new WebSocket(this.url);

        this.ws.onopen = () => {
          console.log('WebSocket connected');
          this.isConnected = true;
          this.connectionStartTime = Date.now();
          this.reconnectAttempts = 0;
          this.currentReconnectDelay = this.initialReconnectDelay;

          // Authenticate
          this.authenticate();

          // Start heartbeat
          this.startHeartbeat();

          // Process queued messages
          this.processMessageQueue();

          resolve(true);
        };

        this.ws.onmessage = (event) => {
          this.handleMessage(event.data);
        };

        this.ws.onerror = (error) => {
          console.error('WebSocket error:', error);
          this.isConnected = false;
          this.isAuthenticated = false;
        };

        this.ws.onclose = () => {
          console.log('WebSocket disconnected');
          this.isConnected = false;
          this.isAuthenticated = false;
          this.stopHeartbeat();
          this.attemptReconnect();
        };
      } catch (error) {
        console.error('Failed to create WebSocket:', error);
        resolve(false);
      }
    });
  }

  /**
   * Authenticate with server using JWT token
   */
  private authenticate(): void {
    const authMessage = {
      type: 'authenticate',
      sessionId: this.sessionId,
      userId: this.userId,
      timestamp: new Date().toISOString(),
      token: this.token
    } as WebSocketMessage;

    this.sendRaw(authMessage);
  }

  /**
   * Send a message to the server
   */
  async send(message: Omit<WebSocketMessage, 'sessionId' | 'userId' | 'timestamp'>): Promise<boolean> {
    if (!this.isConnected || !this.isAuthenticated) {
      // Queue message for later
      this.messageQueue.push({
        ...message,
        sessionId: this.sessionId,
        userId: this.userId,
        timestamp: new Date().toISOString()
      } as WebSocketMessage);
      return false;
    }

    const fullMessage = {
      ...message,
      sessionId: this.sessionId,
      userId: this.userId,
      timestamp: new Date().toISOString()
    } as WebSocketMessage;

    return this.sendRaw(fullMessage);
  }

  /**
   * Send raw message
   */
  private sendRaw(message: Record<string, any>): boolean {
    if (!this.ws || this.ws.readyState !== WebSocket.OPEN) {
      return false;
    }

    try {
      this.ws.send(JSON.stringify(message));
      this.stats.messagesSent++;
      this.stats.lastMessageTime = new Date().toISOString();
      return true;
    } catch (error) {
      console.error('Failed to send message:', error);
      return false;
    }
  }

  /**
   * Handle incoming message
   */
  private handleMessage(data: string): void {
    try {
      const message = JSON.parse(data) as WebSocketMessage;
      this.stats.messagesReceived++;

      // Calculate latency
      const messageTime = new Date(message.timestamp).getTime();
      const latency = Date.now() - messageTime;
      this.latencies.push(latency);
      if (this.latencies.length > 100) {
        this.latencies.shift();
      }
      this.stats.averageLatency = this.latencies.reduce((a, b) => a + b, 0) / this.latencies.length;

      // Handle authentication response
      if (message.type === 'authenticated') {
        this.isAuthenticated = true;
        this.userId = message.userId;
        console.log('WebSocket authenticated');
        return;
      }

      // Handle heartbeat
      if (message.type === 'pong') {
        return;
      }

      // Dispatch to handlers
      const handlers = this.messageHandlers.get(message.type) || [];
      handlers.forEach(handler => {
        try {
          handler(message);
        } catch (error) {
          console.error(`Error in message handler for ${message.type}:`, error);
        }
      });
    } catch (error) {
      console.error('Failed to parse message:', error);
    }
  }

  /**
   * Register message handler
   */
  on(messageType: string, handler: (message: WebSocketMessage) => void): void {
    if (!this.messageHandlers.has(messageType)) {
      this.messageHandlers.set(messageType, []);
    }
    this.messageHandlers.get(messageType)!.push(handler);
  }

  /**
   * Unregister message handler
   */
  off(messageType: string, handler: (message: WebSocketMessage) => void): void {
    const handlers = this.messageHandlers.get(messageType);
    if (handlers) {
      const index = handlers.indexOf(handler);
      if (index > -1) {
        handlers.splice(index, 1);
      }
    }
  }

  /**
   * Start heartbeat
   */
  private startHeartbeat(): void {
    this.heartbeatTimer = setInterval(() => {
      if (this.isConnected) {
        this.sendRaw({
          type: 'ping',
          sessionId: this.sessionId,
          userId: this.userId,
          timestamp: new Date().toISOString()
        });
      }
    }, this.heartbeatInterval);
  }

  /**
   * Stop heartbeat
   */
  private stopHeartbeat(): void {
    if (this.heartbeatTimer) {
      clearInterval(this.heartbeatTimer);
      this.heartbeatTimer = null;
    }
  }

  /**
   * Process queued messages
   */
  private processMessageQueue(): void {
    while (this.messageQueue.length > 0 && this.isConnected && this.isAuthenticated) {
      const message = this.messageQueue.shift();
      if (message) {
        this.sendRaw(message);
      }
    }
  }

  /**
   * Attempt to reconnect
   */
  private attemptReconnect(): void {
    if (this.reconnectAttempts >= this.maxReconnectAttempts) {
      console.error('Max reconnection attempts reached');
      return;
    }

    this.reconnectAttempts++;
    this.stats.reconnectAttempts++;

    console.log(`Attempting to reconnect (${this.reconnectAttempts}/${this.maxReconnectAttempts}) in ${this.currentReconnectDelay}ms`);

    setTimeout(() => {
      this.connect();
    }, this.currentReconnectDelay);

    // Exponential backoff
    this.currentReconnectDelay = Math.min(
      this.currentReconnectDelay * 2,
      this.maxReconnectDelay
    );
  }

  /**
   * Disconnect from server
   */
  disconnect(): void {
    this.stopHeartbeat();
    if (this.ws) {
      this.ws.close();
      this.ws = null;
    }
    this.isConnected = false;
    this.isAuthenticated = false;
  }

  /**
   * Get connection status
   */
  getStatus(): {
    connected: boolean;
    authenticated: boolean;
    stats: ConnectionStats;
  } {
    return {
      connected: this.isConnected,
      authenticated: this.isAuthenticated,
      stats: {
        ...this.stats,
        connectionDuration: this.connectionStartTime > 0 ? Date.now() - this.connectionStartTime : 0
      }
    };
  }

  /**
   * Check if connected
   */
  isReady(): boolean {
    return this.isConnected && this.isAuthenticated;
  }
}

export default SecureWebSocketClient;

/**
 * WebSocket Connection Manager
 * Handles WebSocket connections with automatic reconnection, message queuing, and heartbeat
 */

export type MessageType = 'join' | 'leave' | 'edit' | 'presence' | 'comment' | 'sync' | 'ack' | 'error';

export interface CollaborationMessage {
  type: MessageType;
  sessionId: string;
  userId: string;
  timestamp: number;
  data: any;
  revision?: number;
  messageId?: string;
}

export interface WebSocketConfig {
  url: string;
  reconnectAttempts?: number;
  reconnectDelay?: number;
  maxReconnectDelay?: number;
  heartbeatInterval?: number;
  messageQueueSize?: number;
}

export class WebSocketManager {
  private ws: WebSocket | null = null;
  private url: string;
  private reconnectAttempts: number = 5;
  private reconnectDelay: number = 1000;
  private maxReconnectDelay: number = 30000;
  private heartbeatInterval: number = 30000;
  private messageQueueSize: number = 1000;

  private currentAttempt: number = 0;
  private messageQueue: CollaborationMessage[] = [];
  private heartbeatTimer: NodeJS.Timeout | null = null;
  private reconnectTimer: NodeJS.Timeout | null = null;
  private messageHandlers: Map<string, (message: CollaborationMessage) => void> = new Map();
  private connectionCallbacks: ((connected: boolean) => void)[] = [];
  private isConnected: boolean = false;
  private userId: string = '';
  private sessionId: string = '';

  constructor(config: WebSocketConfig) {
    this.url = config.url;
    this.reconnectAttempts = config.reconnectAttempts || 5;
    this.reconnectDelay = config.reconnectDelay || 1000;
    this.maxReconnectDelay = config.maxReconnectDelay || 30000;
    this.heartbeatInterval = config.heartbeatInterval || 30000;
    this.messageQueueSize = config.messageQueueSize || 1000;
  }

  /**
   * Connect to WebSocket server
   */
  public connect(userId: string, sessionId: string): Promise<void> {
    return new Promise((resolve, reject) => {
      try {
        this.userId = userId;
        this.sessionId = sessionId;

        const wsUrl = `${this.url}?userId=${userId}&sessionId=${sessionId}`;
        this.ws = new WebSocket(wsUrl);

        this.ws.onopen = () => {
          console.log('WebSocket connected');
          this.isConnected = true;
          this.currentAttempt = 0;
          this.startHeartbeat();
          this.flushMessageQueue();
          this.notifyConnectionChange(true);
          resolve();
        };

        this.ws.onmessage = (event) => {
          this.handleMessage(event.data);
        };

        this.ws.onerror = (error) => {
          console.error('WebSocket error:', error);
          reject(error);
        };

        this.ws.onclose = () => {
          console.log('WebSocket disconnected');
          this.isConnected = false;
          this.stopHeartbeat();
          this.notifyConnectionChange(false);
          this.attemptReconnect();
        };
      } catch (error) {
        reject(error);
      }
    });
  }

  /**
   * Disconnect from WebSocket server
   */
  public disconnect(): void {
    this.stopHeartbeat();
    if (this.reconnectTimer) {
      clearTimeout(this.reconnectTimer);
    }
    if (this.ws) {
      this.ws.close();
      this.ws = null;
    }
    this.isConnected = false;
    this.messageQueue = [];
  }

  /**
   * Send message to server
   */
  public sendMessage(message: CollaborationMessage): void {
    if (!this.isConnected || !this.ws) {
      this.queueMessage(message);
      return;
    }

    try {
      this.ws.send(JSON.stringify(message));
    } catch (error) {
      console.error('Failed to send message:', error);
      this.queueMessage(message);
    }
  }

  /**
   * Register message handler for specific type
   */
  public onMessage(type: MessageType, handler: (message: CollaborationMessage) => void): void {
    this.messageHandlers.set(type, handler);
  }

  /**
   * Register connection state callback
   */
  public onConnectionChange(callback: (connected: boolean) => void): void {
    this.connectionCallbacks.push(callback);
  }

  /**
   * Get connection status
   */
  public isConnectedStatus(): boolean {
    return this.isConnected;
  }

  /**
   * Get message queue size
   */
  public getQueueSize(): number {
    return this.messageQueue.length;
  }

  // Private methods

  private handleMessage(data: string): void {
    try {
      const message: CollaborationMessage = JSON.parse(data);
      const handler = this.messageHandlers.get(message.type);
      if (handler) {
        handler(message);
      }
    } catch (error) {
      console.error('Failed to parse message:', error);
    }
  }

  private queueMessage(message: CollaborationMessage): void {
    if (this.messageQueue.length >= this.messageQueueSize) {
      console.warn('Message queue full, dropping oldest message');
      this.messageQueue.shift();
    }
    this.messageQueue.push(message);
  }

  private flushMessageQueue(): void {
    while (this.messageQueue.length > 0 && this.isConnected && this.ws) {
      const message = this.messageQueue.shift();
      if (message) {
        try {
          this.ws.send(JSON.stringify(message));
        } catch (error) {
          console.error('Failed to flush queued message:', error);
          this.messageQueue.unshift(message);
          break;
        }
      }
    }
  }

  private startHeartbeat(): void {
    this.heartbeatTimer = setInterval(() => {
      if (this.isConnected && this.ws) {
        try {
          this.ws.send(JSON.stringify({
            type: 'ping',
            timestamp: Date.now(),
          }));
        } catch (error) {
          console.error('Failed to send heartbeat:', error);
        }
      }
    }, this.heartbeatInterval);
  }

  private stopHeartbeat(): void {
    if (this.heartbeatTimer) {
      clearInterval(this.heartbeatTimer);
      this.heartbeatTimer = null;
    }
  }

  private attemptReconnect(): void {
    if (this.currentAttempt >= this.reconnectAttempts) {
      console.error('Max reconnection attempts reached');
      return;
    }

    this.currentAttempt++;
    const delay = Math.min(
      this.reconnectDelay * Math.pow(2, this.currentAttempt - 1),
      this.maxReconnectDelay
    );

    console.log(`Attempting to reconnect in ${delay}ms (attempt ${this.currentAttempt}/${this.reconnectAttempts})`);

    this.reconnectTimer = setTimeout(() => {
      this.connect(this.userId, this.sessionId).catch((error) => {
        console.error('Reconnection failed:', error);
      });
    }, delay);
  }

  private notifyConnectionChange(connected: boolean): void {
    this.connectionCallbacks.forEach((callback) => {
      try {
        callback(connected);
      } catch (error) {
        console.error('Error in connection callback:', error);
      }
    });
  }
}

/**
 * Create WebSocket manager instance
 */
export function createWebSocketManager(config: WebSocketConfig): WebSocketManager {
  return new WebSocketManager(config);
}

